    for k, v in overview.items():
        print(f'  {k}: {type(v)}')
        if isinstance(v, list) and len(v) > 0:
            print(f'    first: {v[0]}')
elif isinstance(overview, list):
    for g in overview[:5]:
        print(f'  {g}')
