print('\\n=== S1 Insights (top-level) ===')
for k, v in insights.items():
    if not isinstance(v, (list, dict)):
        print(f'{k}: {v}')
    elif isinstance(v, dict):
        print(f'{k}: {list(v.keys())[:5]}')
    elif isinstance(v, list) and len(v) > 0:
        print(f'{k}: [{len(v)} items, first: {v[0]}]')

# Check quality expectations
print('\\n=== S1 Quality Details ===')
if 'quality' in insights:
    q = insights['quality']
    for k, v in q.items():
        print(f'  {k}: {v}')
if 'pricing' in insights:
    p = insights['pricing']
    for k, v in p.items():
        print(f'  {k}: {v}')
"

